#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, X, Y; scanf("%d %d %d", &N, &X, &Y);
        int required = X + 2 * Y;
        if(required <= N) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

